_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_fc_main, vUv ).xyz;

    // darken (decay) over uTime
    if((ret.x+ret.y+ret.z)*.333 <= .33){
      ret -= 0.2;
    }

    ret -= abs(vRadius-1)*.003;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture( sampler_pc_main, vUv ).xyz;

    vec2 uv2 = vUv;
    uv2.x = uv2.x+.005;
    uv2.y = uv2.y+.005;
    vec3 retd = texture( sampler_pc_main, uv2 ).xyz;
    retd = retd - .85;
    ret = mix(abs(ret-.95), retd, ret-.2);
    if(ret.x >= .5 && ret.y >= .5 && ret.z >= .5){ret = 0;}

    int c = 1;
    while (c <= 3){
       uv2.x = vUv.x*(1-(c*.25))+((c*.25)*.5);
       uv2.y = vUv.y*(1-(c*.25))+((c*.25)*.5);

       vec3 clamp;
       clamp.x = min(int(ret.x+.9),1);
       clamp.y = min(int(ret.y+.9),1);
       clamp.z = min(int(ret.z+.9),1);
       clamp = lum(clamp);
       clamp = clamp;

       vec3 ret2 = texture( sampler_pc_main, uv2 ).xyz;

       float tmp;

       if(c == 1){
         tmp = ret2.x;
         ret2.x = ret2.z;
         ret2.z = ret2.y;
         ret2.y = tmp;
       }else if(c == 2){
         tmp = ret2.x;
         ret2.x = ret2.y;
         ret2.y = ret2.z;
         ret2.z = tmp;
       }

       ret = mix(ret2-(0+(c*.15)),ret,clamp);
       //ret = clamp;
       c++;
    }

    vec3 blr = GetBlur3(vUv);
    blr = lum(pow(blr,2))*.95 - .005;

    ret = mix(blr,max(ret*1.15,0),.5+.5*sin(vRadius*8+uTime)-min(q4*.75-.25,1));


  fragColor = ret;
}
